import React, { useState } from 'react';
import Modal from '@mui/material/Modal';
import Box from '@mui/material/Box';
import MenuIcon from '@mui/icons-material/Menu';
import EmojiEventsIcon from '@mui/icons-material/EmojiEvents';
import GroupsIcon from '@mui/icons-material/Groups';
import CodeIcon from '@mui/icons-material/Code';
import SkillManager from '../components/SkillManager';
import DrawerMenu from '../components/DrawerMenu';
import ContestCard from '../components/ContestCard';
import ContestModal from '../components/ContestModal';
import Header from '../components/Header';
import FeedbackButtons from '../components/FeedbackButtons';
import { useNavigate } from 'react-router-dom';
import './Home.css';

const dummyUsers = [
  { id: 1, name: "홍길동", skills: ["React", "JavaScript"] },
  { id: 2, name: "김철수", skills: ["Python", "Django"] },
  { id: 3, name: "이영희", skills: ["Java", "Spring"] },
  { id: 4, name: "박민수", skills: ["C++", "알고리즘"] },
  { id: 5, name: "최지우", skills: ["UI/UX", "Figma"] },
  { id: 6, name: "정우성", skills: ["Node.js", "Express"] },
  { id: 7, name: "한지민", skills: ["DB", "SQL"] },
  { id: 8, name: "서준호", skills: ["React", "TypeScript"] },
  { id: 9, name: "오세훈", skills: ["AI", "TensorFlow"] },
  { id: 10, name: "임수정", skills: ["Flutter", "모바일"] },
];

function Home() {
  const [modalOpen, setModalOpen] = useState(false);
  const [userSkills, setUserSkills] = useState(["React", "JavaScript"]);
  const [users] = useState(dummyUsers);
  const [matched, setMatched] = useState([]);
  const [feedbacks, setFeedbacks] = useState({});
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [openMenus, setOpenMenus] = useState({});
  const navigate = useNavigate();

  const matchTeam = () => {
    const shuffled = [...users].sort(() => Math.random() - 0.5);
    setMatched([shuffled.slice(0, 5), shuffled.slice(5, 10)]);
  };

  const handleFeedback = (teamIndex, isPositive) => {
    setFeedbacks(prev => ({ ...prev, [teamIndex]: isPositive }));
  };

  return (
    <div className="home-container">
      {/* 헤더 */}
      <header className="home-header">
        <div className="logo">TUP!</div>
        {!drawerOpen && (
          <button className="menu-button" onClick={() => setDrawerOpen(true)}>
            <MenuIcon style={{ fontSize: '2.2rem', color: '#FF6B35' }} />
          </button>
        )}
      </header>

      {/* 드로어 메뉴 */}
      <DrawerMenu
        open={drawerOpen}
        onClose={() => setDrawerOpen(false)}
        openMenus={openMenus}
        onToggle={setOpenMenus}
      />

      {/* 소개 섹션 */}
      <section className="intro-section">
        <h2>
          함께할 <span className="highlight">팀원</span>이 필요하신가요?
        </h2>
        <p className="subtext">
          <span className="highlight">TUP!</span>은 공모전 참가자들을 위한 지능형 팀 매칭 플랫폼입니다.<br />
          기술 스택과 관심사를 기반으로 최적의 팀원을 찾아보세요!
        </p>
        <span className="down-arrow">⬇</span>
      </section>

      {/* 팀매칭 선택 섹션 */}
      <section className="match-section">
        <div className="match-card">
          <h3>AutoTeamUp</h3>
          <p>공모전을 먼저 선택하여, 빠르게 팀원 그룹을 구성할 수 있어요.</p>
          <button onClick={() => navigate('/TeamMatching1')}>빠르게 팀 결성하기</button>
        </div>
        <div className="match-card">
          <h3>OpenTeamUp</h3>
          <p>공모전, 분야, 팀장을 직접 고르고 자유롭게 팀을 이뤄보세요.</p>
          <button onClick={() => navigate('/TeamMatching2')}>자유롭게 팀 결성하기</button>
        </div>
      </section>

      {/* 공모전 카드 */}
      <section className="contest-section">
        <div className="contest-card" onClick={() => setModalOpen(true)}>
          <img src="/aws.png" alt="공모전 이미지" />
          <div className="contest-info">
            <h4>2025 AWS x Codetree 프로그래밍 경진대회</h4>
            <p>마감: 2025년 05월 16일 (D-14)</p>
          </div>
        </div>
      </section>

      {/* 모달 */}
      <ContestModal
        open={modalOpen}
        onClose={() => setModalOpen(false)}
        users={users}
        userSkills={userSkills}
        setUserSkills={setUserSkills}
        matched={matched}
        matchTeam={matchTeam}
        feedbacks={feedbacks}
        onFeedback={handleFeedback}
      />
    </div>
  );
}

export default Home;
